<template><div class="page-container"><div class="page-card"><div class="page-header"><span class="page-title">活动管理</span><a-button type="primary" @click="onCreate"><plus-outlined/>新建活动</a-button></div><DataTable :columns="cols" :data-source="list" :loading="ld" :total="t" v-model:page="p" v-model:page-size="ps"><template #cover="{r}"><a-image :src="r.cover" :width="80" :height="50" style="object-fit:cover;border-radius:4px"/></template><template #status="{r}"><a-tag :color="r.status==='running'?'green':r.status==='ended'?'default':'blue'">{{r.status==='running'?'进行中':r.status==='ended'?'已结束':'草稿'}}</a-tag></template><template #a="{r}"><a-space><a @click="onEdit(r)">编辑</a></a-space></template></DataTable></div></div></template>
<script setup lang="ts">import {ref} from 'vue';import {message} from 'ant-design-vue';import {PlusOutlined} from '@ant-design/icons-vue';import {marketingApi} from '@/api/marketing';import DataTable from '@/components/common/DataTable.vue'
const ld=ref(false),list=ref<any[]>([]),t=ref(0),p=ref(1),ps=ref(20);const cols=[{title:'封面',dataIndex:'cover',width:100,slot:'cover'},{title:'标题',dataIndex:'title',width:200},{title:'类型',dataIndex:'type',width:80},{title:'开始',dataIndex:'startTime',width:160},{title:'结束',dataIndex:'endTime',width:160},{title:'参与',dataIndex:'participantCount',width:70},{title:'状态',dataIndex:'status',width:80,slot:'status'},{title:'操作',dataIndex:'action',width:80,slot:'a'}]
async function ft(){ld.value=true;try{const r=await marketingApi.getActivityList({page:p.value,pageSize:ps.value});list.value=r.data.data?.list||r.data?.list||[];t.value=r.data.data?.total||0}catch{}finally{ld.value=false}}
function onCreate(){message.info('新建活动')};function onEdit(_:any){message.info('编辑活动')}
ft();
</script>
